{
    "level": "A1–B1",
    "intro": "]W tej sekcji poznasz <strong>różne typy zdań pytających</strong> w języku angielskim: od prostych pytań ogólnych po pytania złożone.",
    "rules": [
        {
            "label": "Tak/Nie Pytania",
            "color": "emerald",
            "text": "<strong>Pytania ogólne</strong> – odpowiedź brzmi „tak” lub „nie”:",
            "example": "Czy lubisz kawę?"
        },
        {
            "label": "Co-Pytania",
            "color": "blue",
            "text": "<strong>Pytania specjalne</strong> – ze słowami pytającymi:",
            "example": "Co chcesz?"
        },
        {
            "label": "Tagi pytań",
            "color": "rose",
            "text": "<strong>Pytania do rozdziałów</strong> — dla potwierdzenia:",
            "example": "Lubisz herbatę, prawda?"
        }
    ]
}
